INSERT INTO `articles` (`id`, `title`, `content`) VALUES
(1, 'اعراض الامراض', '# الماريك\nتظهر أعراض المرض في شكل بطء في النمو مع شلل في الأرجل والأجنحة حيث يمشى الطائر بطريقه غير طبيعيه ثم يفقد بعد ذلك السيطرة على أرجله التي يحدث بها عرج ثم تلتوي أصابع الرجل مع تقوس مفصل الركبة وضمور عضلات الفخذ مع ظهور إسهال مائي مصفر اللون ذو رائحة كريهة مع عدم قدره الطائر على الحركة للوصول إلى المعالف والمساقي مما يحدث هزال شديد لهذه الطيور نتيجة للجوع والعطش وتموت كما انه قد تظهر الإصابة أحيانا في العين بتغير لونها إلى الرمادي مع اختفاء الخطوط الإشاعيه وتشوه القزاحيه وتقل قدرتها على الاستجابة للضوء وتضيق تدريجيا وقد يصاب الطائر بالعمى.\n\n# النيوكاسل\nتظهر الأعراض على الطائر في البداية كأعراض تنفسيه حيث يفتح الطائر فمه مع رقبته ليحصل على أكبر قدر من الهواء مما يؤدى لسماع أصوات حشرجة نتيجة لدخول الهواء في القصبة الهوائية وتزداد تلك الحالة ليلا ينبع ذلك حدوث إسهال للطائر يكون أخضر اللون ممتزجا بالإفرازات الجيرية البيضاء ويتحول لون العرف والدلايات إلى اللون الأحمر الداكن أو الأزرق مع حدوث عسر للهضم وبقاء الغذاء في الحوصلة ممتزجا بسائل بني اللون رائحته حمضيه كريهة مع نزول لعاب بكميات كبيره من الفم مع فقد الشهية للطعام والشراب ثم تحدث بعد ذلك الأعراض العصبية مثل الارتعاش العنيف وشلل الأطراف وانثناء الرقبة لأعلى أو أسفل وعدم التوازن والطيران في الهواء ثم الوقوع على الأرض بشده ثم يموت الطائر.  \nوفي حالة الطيور البالغة يحدث انخفاض واضح في إنتاج البيض يتراوح ما بين 20 - 50% وقد يتوقف تماما مع إنتاج بيض قشرة (برشت) أو تكون القشرة ضعيفة وهشة.\n\n# الالتهاب الشعبي المعدي\nتظهر الأعراض في صوره إفرازات مخاطية من الأنف والعين وتورم الجيوب الأنفية مصحوبة بسعال وعطس وحشرجة عاليه في الصوت مع مد الطائر رقبته إلى الأمام ليتمكن من التخلص من السوائل المتجمعة في المسالك التنفسية كذلك يحدث انخفاض في استهلاك العلف مع نقص شديد في الوزن يصاحبه انخفاض في إنتاج البيض مع التأثير على نوعيه القشرة كأن تلين وتكون رقيقه وتتشوه وتتعرج ويعمل على زيادة هذه الأعراض عوامل الإجهاد مثل الظروف المناخية والإدارة والتغذية الرديئة ونقل الطيور من عنبر إلى أخر وعمليات التحصين.\n\n# الجامبورو\nتظهر الأعراض فجأة بالقطيع وتنتشر بسرعة كبيرة في صورة خمول وكسل عام للطائر مع عدم الرغبة في الحركة مع رقاد الطائر وامتناعه عن الأكل والشرب مع حدوث إسهال مائي مصفر رغوي مع أبتلال ريش نطقه المجمع مع التهابها مما يحفز الطيور على نقر تلك المنطقة ونسبه الطيور المريضة تكون مرتفعة حيث تتراوح نسبه النفوق ما بين 10 - 30% تكون أعلى نسبه نفوق في اليوم الثالث من ظهور المرض ثم تنخفض بعد ذلك في خلال خمسة أيام.\n\n# الجدري\nتظهر أعراض هذا المرض في الدجاج في صوره بثور على العرف والدلايات وقد تمتد إلى باقي الأجزاء الغير مغطاة بالريش والبثور يكون لونها بني غامق ومرتفعه عن سطح الجلد وعند إزالتها تترك مكانها منطقه مدممه وقد تصاب الأنف والفم مما يعيق التنفس والأكل وأيضا قد يصيب جفون العين مما يؤدى إلى إعاقة النظر أو العمى.  \nويصيب مرض الجدري عاده الطيور البالغة (5 - 12 شهر من العمر) ويسبب انخفاض واضح في إنتاج البيض.\n'),
(2, 'اخطاء في التربية', 'تربية الفراخ البيضاء يمكن أن تكون صعبة ومليئة بالتحديات، والتي يمكن أن تؤدي إلى ارتكاب أخطاء قد تؤثر على صحة وسلامة الفراخ. إليك أخطاء شائعة في تربية الفراخ البيضاء:\r\n\r\n- عدم توفير مساحة كافية للفراخ، مما يؤدي إلى الازدحام والإصابة بالأمراض.\r\n- تغذية الفراخ بغذاء غير مناسب أو غير متوازن، مما يؤدي إلى نمو غير صحي وضعف الجهاز المناعي.\r\n- عدم توفير مياه نظيفة وعذبة بشكل دائم، مما يؤدي إلى الجفاف والإصابة بالأمراض.\r\n- عدم توفير الإضاءة الطبيعية أو الاصطناعية اللازمة للفراخ، مما يؤدي إلى فقدان الرؤية والصحة العامة.\r\n- عدم توفير درجة حرارة مناسبة للفراخ، خاصة في الأشهر الأولى من حياتها، مما يؤدي إلى الإصابة بالبرد والأمراض الناتجة عنه.\r\n- عدم توفير تهوية مناسبة للمساحة المخصصة للفراخ، مما يؤدي إلى ارتفاع درجة الرطوبة وتراكم البكتيريا والأمراض.\r\n- عدم تنظيف المساحة المخصصة للفراخ بشكل منتظم، مما يؤدي إلى تراكم الروائح الكريهة والبكتيريا والأمراض.\r\n- عدم توفير الرعاية الصحية المناسبة للفراخ، مما يؤدي إلى الإصابة بالأمراض والإصابات والعدوى.\r\n- تجاهل علامات المرض وعدم اتخاذ الإجراءات اللازمة لعلاج الفراخ المصابة بالأمراض.\r\n- عدم توفير الأمان والحماية المناسبة للفراخ، مما يؤدي إلى الهروب والإصابة بالحيوانات المفترسة والطيور الجارحة.\r\n'),
(3, 'علاج الامراض', '# الماريك\nتربيه سلالات من الطيور يكون لها مقدره وراثية عاليه لمقاومه المرض. الاهتمام بتهوية وتطهير العنابر بالفورمالين 3% أو الصودا الكاوية 1% لأنهما يمكنهما القضاء على الفيروس فورا وعدم تربيه أعمار مختلفة من الكتاكيت في نفس المزرعة وأيضا عدم تذبذب درجات الحرارة بالارتفاع والانخفاض مما يسبب للطيور نزلات برد مع العوامل المجهدة الأخرى كنقص التغذية أو الزحام أو سوء التهوية مما يؤدى إلى نفوق مرتفع وعدم الاستفادة من اللقاح المستخدم. التحصين ضد المرض بلقاح الماريك وذلك بإذابة اللقاح في المحلول المذيب المرفق معه والحقن بمعدل 0.2سم / كتكوت في عضله الفخذ أو تحت جلد الرقبة وذلك عند الفقس مباشره.\n\n# النيوكاسل\nالتحصين ضد المرض باللقاح المناسب وفي الأوقات المناسبة يعتبر أهم الإجراءات المتبعة للحماية من المرض وهناك العديد من اللقاحات الحية والميتة ويعد اللقاح عتره هتشنر ب1 وعتره لاسوتا من أهم اللقاحات المستخدمة في مصر وذلك عن طريق الرش أو التغطيس أو مياه الشرب وكذلك استخدام اللقاح الميت بالحقن العضلي للطيور وذلك وفق برنامج التحصين الموجود بنهاية النشرة. العمل على تجنب العوامل المساعدة على إضعاف القطيع مثل الظروف البيئية السيئة كالبرودة أو الحرارة الشديدة والتي تؤثر على حيوية القطيع. كذلك توفير العلائق الغذائية الكاملة المتوازنة في محتواها من العناصر حيث أن عدم اتزان العلائق ونقص كمياتها تؤدى إلى تقليل مقاومه الطائر. كما أن التهوية السيئة تؤدى إلى زيادة الرطوبة وزيادة غاز الأمونيا الذي يسبب أمراض تنفسيه تهيئ من إصابة القطيع. مراعاة الشروط الصحية بالمزرعة مثل تنفيذ برامج التطهير بكل دقه وعناية مع منع دخول الغرباء للمزرعة وعمل برنامج مكافحه للقوارض والكلاب والقطط حيث أنها من العوامل المساعدة على نقل المرض من مزرعة إلى أخرى مع إعدام الطيور النافقة وحرقها ودفنها وعدم إلقائها في العراء.\n\n# الالتهاب الشعبي المعدي\nإذا ظهر المرض وكان ذلك في فصل الشتاء يتم رفع درجه حرارة العنبر بحوالي 4-5 درجات عن المعدل مع زيادة التهوية به للتخلص من غاز الأمونيا. حقن مضاد حيوي استربتومايسين بمعدل 100-200 ملجم / الطائر أو إضافته كلورتتراسيكلين أو أثرومايسين على العلف بمعدل 200جم / الطن لمدة 7-10 يوم كعلاج أعراض الإصابة بالبكتريا الثانوية. يراعى التحصين للطيور ضد المرض باللقاح الحي ( هـ 120 ) عند عمر 3-4 أسابيع وتكرر عند 4-12 أسبوع أما الجرعة الثالثة فتكون باللقاح الميت عند عمر 14-18 أسبوع مع ملاحظة عدم تأخير التحصين لقرب موعد إنتاج البيض لأن ذلك يعمل على انخفاض إنتاج البيض بشكل ملحوظ.\n\n# الجامبورو\nنظرا لآن الإصابة بذلك المرض تؤثر على الجهاز المناعي بالجسم مما يتبع ذلك ضعف الاستجابة للقاحات الأخرى للأمراض الأخرى وقابليه الطائر للإصابة بأمراض أخرى لذا فإن الوقاية من هذا المرض تكون بالالتزام بتطبيق برنامج جيد للتطعيم للحصول على أحسن النتائج ويكون ذلك بتلقيح الطيور باللقاح الحي في الأعمار المبكرة وباللقاح الميت لقطيع الأمهات قبل البلوغ.\n\n# الجدري\nعدم تربيه أعمار مختلفة من الطيور في نفس المزرعة حيث أن العدو بالفيروس من السهل أن تظهر في قطيع صغير في العمر غير محصن إذا حصن قطيع أخر أكبر منه بنفس المزرعة. عدم تربيه أكثر من نوع واحد من الطيور بنفس المزرعة لأن المرض يمكن أن ينتقل بين الأنواع المختلفة. وجد أن التحصين ضد المرض يعتبر الطريقة الوحيدة المضمونة للوقاية من المرض ولكن يراعى الآتي عند التحصين: الوقت الأمثل للتحصين يكون عند عمر 8 -12 أسبوع. يجب عدم تحصين الدجاج البياض لأن ذلك سيؤدى إلى انخفاض إنتاجيه البيض وحدوث القلش للطيور. يجب تحصين المزرعة كلها في وقت واحد وهنا تظهر أهميه تربيه قطعان متقاربة في العمر. يتم إذابة أنبول اللقاح 1000 جرعه في حوالي 25 سم من الماء المقطر مع مراعاة عدم تناثر اللقاح بالمزرعة وإعدام الأمبولات الفارغة بعد الحقن. يتم وخذ جلد الجناح بالإبر المزدوجة المجوفة حيث أنها ابره مجوفة بها شق طولي ليسمح بالتقاط قطره من قطرات اللقاح مع مراعاة غمس إبره بالمحلول بين كل وخزه وأخرى. يتم التحصين للطيور السليمة فقط الغير مريضه بأي مرض وفي الحالة التحصين الناجح يظهر تورم محمر مكان الوخز بعد 7-10 أيام من التحصين وإذا لم يظهر تورم دل ذلك على فساد التحصين ويعاد التحصين مره أخرى. العلاج في حاله ظهور المرض في قطيع غير محصن يتم تحصينه باللقاح فورا ولكن يجب مراعاة البدء بتحصين الطيور السليمة والانتهاء بالطيور المصابة. عزل الطيور المصابة وإزالة البثور الموجودة في الأماكن المصابة مع دهان مكان البثرة بمحلول يود - جلسرين بنسبه 1-4. يتم تقديم المضادات الحيوية ( تيراميسين أو أرثرومايسين ) بمعدل 20 ملجم / الدجاجة لمده 3-5 أيام مع تقديم فيتامين (أ) في مياه الشرب أو حقنها في العضل كعلاج ثانوي للبكتريا ولرفع المناعة. يتم وضع محلول مطهر في ماء الشرب مثل برمنجانات البوتاسيوم 10000:1 أو أحد مركبات الكلور أو اليود خلال فتره المرض ومره كل أسبوع بعد انتهائه.\n'),
(4, 'الارضية', 'تعتبر الأرضية من أهم العوامل التي يجب الانتباه إليها في تربية الفراخ البيضاء حيث تؤثر بشكل كبير على صحة وراحة الدجاج وإنتاجيتهم. وبالتالي، يجب اختيار الأرضية المناسبة التي تتناسب مع احتياجات الدجاج ومتطلباتهم. وفيما يلي نقاط يجب اتخاذها بعين الاعتبار عند اختيار الأرضية لتربية الفراخ البيضاء:\r\n\r\n# نوع الأرضية\r\nتوجد عدة خيارات للأرضية المناسبة لتربية الفراخ البيضاء وتشمل القش الشنارة والأرضيات البلاستيكية. ويجب اختيار الأرضية المناسبة التي تتوافق مع سلالة الفراخ وظروف البيئة المحيطة. ويفضل استخدام الأرضيات البلاستيكية لأنها مقاومة للبكتيريا والفطريات وتساعد في تنظيف الأرضية بشكل أسهل وأكثر فعالية.\r\n\r\n# النظافة\r\nيجب الحرص على نظافة الأرضية بشكل دوري ومنتظم، حيث يمكن تكوين بكتيريا وفطريات على الأرضية والتي يمكن أن تؤثر بشكل سلبي على صحة الدجاج. ويجب تنظيف الأرضية بالماء والصابون وتطهيرها باستخدام المواد المعقمة.\r\n\r\n# الحجم\r\nيجب اختيار الأرضية المناسبة حسب عدد الفراخ وحجمها، حيث يجب توفير مساحة كافية للفراخ للحركة والتنقل والنمو. ويجب تجنب تجميع الفراخ في مساحات صغيرة جداً، حيث يؤدي ذلك إلى ارتفاع مستوى التوتر والإجهاد لديهم وتأثير سلبي على صحتهم وإنتاجيتهم.\r\n\r\n# الراحة\r\nيجب الحرص على توفير الراحة للفراخ عند اختيار الأرضية، حيث يجب أن تكون الأرضية ناعمة وخالية من العوائق والأشياء الحادة التي يمكن أن تؤذي الدجاج. ويمكن استخدام الرمل أو القش لزيادة الراحة وتقليل الاحتكاك بين الأرضية والأرجل.\r\n\r\n# الحماية\r\nيجب توفير الحماية للفراخ على الأرضية، حيث يمكن تعرضها للهجوم من الحيوانات المفترسة ويمكن استخدام الشبك الحديدي أو الأسلاك الشائكة لتأمين المكان وحماية الفراخ.\r\n\r\n# التكلفة\r\nيجب اختيار الأرضية التي تتوافق مع الميزانية المتاحة لتربية الفراخ، حيث يمكن أن يكون تكلفة بعض الأرضيات مرتفعة جداً وغير متاحة للجميع. ويجب الاستفادة من الخيارات المتاحة والمناسبة لتوفير الأرضية الملائمة لتربية الفراخ بأفضل صورة ممكنة.\r\n\r\n# النشاره\r\nفرش الأرضية بالنشاره فى الصيف بسمك 5 سم وفى الشتاء 10 سم.\r\n'),
(5, 'الرطوبة', 'تربية الفراخ البيضاء تحتاج إلى اهتمام كبير بمستوى الرطوبة في البيئة التي تعيش فيها، حيث يؤثر ارتفاع أو انخفاض الرطوبة على صحة الفراخ ونموها. فيما يلي نقاط مهمة حول الرطوبة في تربية الفراخ البيضاء:\r\n\r\n# 1- مستوى الرطوبة المناسب\r\nيجب أن يتراوح مستوى الرطوبة في بيئة تربية الفراخ بين 50-70%، حيث إن ارتفاع الرطوبة يزيد من احتمالية ظهور الأمراض الفطرية والجراثيم، في حين يؤدي انخفاض الرطوبة إلى جفاف الجلد والأنسجة الحساسة للفراخ.\r\n\r\n# 2- تهوية البيئة\r\nيجب أن تكون البيئة التي تعيش فيها الفراخ مهواة جيدًا وتحتوي على نظام تهوية فعال، حيث يمكن للتهوية الجيدة التحكم في مستوى الرطوبة والحفاظ عليها في المستوى المناسب.\r\n\r\n# 3- استخدام الأرضيات المناسبة\r\nيجب استخدام أرضيات مصنوعة من مواد تسمح بامتصاص الرطوبة وتسمح بتدفق الهواء، حيث يمكن لهذا النوع من الأرضيات الحفاظ على مستوى الرطوبة في المستوى المناسب وتجنب تراكم الرطوبة في البيئة التي تعيش فيها الفراخ.\r\n\r\n# 4- تحديد مستوى الرطوبة\r\nينصح باستخدام جهاز قياس الرطوبة لتحديد مستوى الرطوبة في البيئة التي تعيش فيها الفراخ، وذلك للتحكم في مستوى الرطوبة والحفاظ على صحة ونمو الفراخ.\r\n\r\n# 5- تنظيف البيئة وتجنب التراكمات\r\nيجب تنظيف البيئة التي تعيش فيها الفراخ بانتظام وتجنب تراكمات المواد العضوية والرطوبة، حيث تزيد هذه التراكمات من مستوى الرطوبة في البيئة.\r\n\r\nباختصار، يجب تحديد مستوى الرطوبة في بيئة تربية الفراخ البيضاء والحفاظ على مستواها في المستوى المناسب، وذلك من خلال تهوية البيئة واستخدام الأرضيات المناسبة وتنظيف البيئة بانتظام.\r\n'),
(6, 'الصيف', 'تتطلب تربية الفراخ البيضاء في فصل الصيف اهتمامًا خاصًا بسبب الظروف الجوية الحارة والجافة التي يمكن أن تؤثر على صحة ونمو الفراخ. فيما يلي نقاط مهمة حول تربية الفراخ البيضاء في الصيف:\r\n\r\n# 1- توفير الظل\r\nيجب توفير مكان ذي ظل للفراخ حتى يتمكنوا من الاستراحة في الأوقات الحارة من النهار.\r\n\r\n# 2- توفير الماء\r\nيجب توفير كميات كافية من الماء النظيف للفراخ للحفاظ على ترطيب أجسادها وتجنب الجفاف، ويمكن إضافة بعض الثلج إلى الماء لتقليل درجة حرارته.\r\n\r\n# 3- نظام التهوية\r\nيجب توفير نظام تهوية فعال في بيئة تربية الفراخ لتقليل درجة حرارة الجو والحفاظ على مستوى الرطوبة المناسب، ويمكن استخدام المراوح أو النوافذ المفتوحة لتحسين التهوية.\r\n\r\n# 4- الغذاء\r\nيجب توفير الغذاء الصحي والمتوازن للفراخ، وينصح بتغذيتها في الأوقات الباردة من النهار لتجنب الإجهاد الحراري.\r\n\r\n# 5- تنظيف البيئة\r\nيجب تنظيف بيئة تربية الفراخ باستمرار لتجنب تراكم الروث والأوساخ التي قد تؤدي إلى زيادة درجة الحرارة وتفاقم الحالة الصحية للفراخ.\r\n\r\n# 6- الحرص على الصحة\r\nيجب مراقبة صحة الفراخ باستمرار واكتشاف أي علامات للمرض مثل الإسهال أو السعال أو التثاءب، والتدخل بسرعة عند الحاجة.\r\n\r\n# 7- التحكم في درجة حرارة البيئة\r\nيجب الحرص على توفير بيئة مناسبة للفراخ من حيث درجة الحرارة، ويمكن استخدام أجهزة تحكم في درجة الحرارة مثل المروحة أو التكييف لتحسين ظروف التربية.\r\n\r\n# 8- توفير الإضاءة الصحيحة\r\nيجب توفير نظام إضاءة صحيح لتربية الفراخ في الصيف، ويجب تجنب إضاءة شديدة السطوع التي يمكن أن تؤثر سلبًا على صحة الفراخ.\r\n\r\n# 9- التحكم في كمية الطعام\r\nيجب توفير كمية مناسبة من الطعام للفراخ وتجنب إطعامها بكميات زائدة، ويجب توزيع الطعام على فترات متعددة خلال اليوم.\r\n\r\n# 10- مراقبة مستويات الرطوبة\r\nيجب تجنب مستويات الرطوبة المرتفعة في بيئة تربية الفراخ، ويمكن استخدام أجهزة تحكم في مستويات الرطوبة مثل الضواغط لتحسين الظروف.\r\n'),
(7, 'الشتاء', 'تربية الفراخ البيضاء في الشتاء يحتاج إلى اهتمام خاص بالظروف البيئية المتغيرة وتوفير بيئة مناسبة للفراخ للحفاظ على صحتها وتحقيق أقصى قدر من الإنتاجية. إليك بعض النقاط التي يمكن توسيعها في هذا الموضوع:\r\n\r\n# 1- توفير درجة حرارة مناسبة\r\nيجب الحرص على توفير درجة حرارة مناسبة للفراخ في فصل الشتاء، ويمكن استخدام الأجهزة الحرارية مثل المدافئ والمراوح لتحقيق هذا الهدف.\r\n\r\n# 2- توفير إضاءة كافية\r\nيجب توفير نظام إضاءة كافي لتربية الفراخ في فصل الشتاء، ويمكن استخدام المصابيح الكهربائية الخاصة بالفراخ لتحقيق هذا الهدف.\r\n\r\n# 3- توفير كمية مناسبة من الطعام\r\nيجب توفير كمية مناسبة من الطعام للفراخ في فصل الشتاء وتجنب إطعامها بكميات زائدة. كما يجب توزيع الطعام على فترات متعددة خلال اليوم.\r\n\r\n# 4- مراقبة مستويات الرطوبة\r\nيجب تجنب مستويات الرطوبة المرتفعة في بيئة تربية الفراخ في فصل الشتاء، ويمكن استخدام أجهزة تحكم في مستويات الرطوبة مثل الضواغط لتحسين الظروف.\r\n\r\n# 5- الحرص على نظام النوم\r\nيجب توفير بيئة هادئة ومظلمة للفراخ للحصول على نوم جيد وتحسين صحتها.\r\n\r\n# 6- الحرص على صحة الفراخ\r\nيجب مراقبة صحة الفراخ باستمرار وتحديد أي مشاكل صحية مبكرًا، ويمكن استشارة الطبيب البيطري في حالة الحاجة.\r\n\r\n# 7- توفير مساحة كافية\r\nيجب توفير مساحة كافية للفراخ للتحرك والتمدد وتجنب التزاحم، ويمكن تخصيص مساحات خاصة للعب والتسلية.\r\n\r\n# 8- الاهتمام بنوعية الفراخ\r\nيجب اختيار فراخ صحية وذات جودة عالية لضمان نمو صحي وإنتاجية جيدة.\r\n\r\n# 9- التدريب على التعرض لدرجات الحرارة الباردة\r\nيمكن تدريب الفراخ على التعرض لدرجات الحرارة الباردة في فصل الشتاء عن طريق تعريضها لدرجات حرارة منخفضة تدريجياً.\r\n\r\n# 10- الاستعداد للطوارئ\r\nيجب تحضير خطة لللتعامل مع الحوادث الطارئة مثل انقطاع التيار الكهربائي أو العواصف الثلجية، ويجب توفير مخزون كافي من الطعام والماء والأدوات الضرورية للتدخل السريع في حالة الحاجة.\r\n\r\nبشكل عام، يجب توفير بيئة صحية ومناسبة لتربية الفراخ البيضاء في فصل الشتاء، والحرص على توفير جميع الظروف اللازمة للحفاظ على صحتها وتحقيق أقصى قدر من الإنتاجية.\r\n'),
(8, 'تجانس الاوزان', 'تربية الفراخ البيضاء في التجانس في الأحجام هو عملية تحقيق توازن مثالي في الحجم بين الفراخ المختلفة في المزرعة وهو يعتبر عاملاً هاماً في تحقيق الإنتاجية والأرباح المرتبطة بتربية الفراخ. إليك بعض النقاط التي يمكن تطبيقها في هذا الموضوع:\r\n\r\n# 1- التحكم في وزن الفراخ\r\nيجب مراقبة وزن الفراخ بشكل دوري وتقييم أحجامها، ويمكن استخدام أدوات الوزن الخاصة بالفراخ لتحقيق ذلك.\r\n\r\n# 2- الاهتمام بمستوى التغذية\r\nيجب توفير كمية كافية من الطعام والمياه النظيفة والصحية للفراخ، وذلك لتحقيق نمو متساوٍ بين الفراخ.\r\n\r\n# 3- توفير مساحة كافية\r\nيجب توفير مساحة كافية للفراخ للتحرك والتمدد وتجنب التزاحم، ويمكن تخصيص مساحات خاصة للعب والتسلية.\r\n\r\n# 4- الاهتمام بنوعية الفراخ\r\nيجب اختيار فراخ صحية وذات جودة عالية لضمان نمو صحي وإنتاجية جيدة، ويمكن الحصول على الفراخ ذات الحجم المتجانس عن طريق اختيار نوعيات فراخ معينة ذات خصائص وراثية متجانسة.\r\n'),
(9, 'الاظلام', '## شرح الاظلام\nالاظلام ليس عبارة عن اطفاء لمبة لبعض الوقت ولكن الاظلام من البرامج التى اذا قمت بادارتها جيدا تسرع من عملية نمو الكتكوت وفتح شهيته وتقوية مناعتة وكسب ما لا يقل عن ١٠ الى ١٥ % زيادة فى الوزن\n- من فوائد الاظلام\nزيادة الوزن وتحسين كفاءة الغذاء من خلال تقليل حركة الطيور وفعاليتها من جهة ومن خلال إعطاء الطيور وقت للنوم والراحة وبالتالي تقليل سرعة مرور المادة الغذائية بالقناة الهضمية والسماح لوقت أطول للامتصاص من جهة أخرى.\n\nتقليل ظهور نسبة التشوهات بالأرجل وحالات الموت المفاجئ وحالات الاستسقاء في البطن وتوفير الكهرباء مع إطالة العمر التشغيلي للمصابيح. الدراسات الحديثة تؤكد على أن النظام الضوئي يعتبر مفتـاح النجاح في تربية السلالات الحديثة لفـروج اللحـم. هذه السلالات تتمتع بسرعة نمو فائقة وذات كفاءة عالية في تحويل الغذاء.\n\nيرتفع مستوى أنزيم الفوسفاتيز القاعدي في الليل ويعتبر هذا الأنزيم مهم في تطور الهيكل العظمي. دورة الظلام والضـوء سـتؤدي إلى زيـادة إفـراز هرمون (الميلاثونين) المهم في تطور الجهاز المناعي. تحسن نسبة التجانس، تصبح الطيور متقاربة بالوزن ونسبة التجانس الجيدة هي 85%. إذا انخفضت إلى 60% فتعتبر نسبة التجانس ضعيفة.\n\n### ملحوظة : يجب توزيع عدد ساعات الإظلام على مدار اليوم بالتساوي'),
(10, 'الامراض', '# هناك العديد من الامراض الخطيرة التى وجب التحذير منها  ومن هذة الامراض\n## الماريك\n\r\nمرض الماريك هو مرض فيروسي سرطاني خبيث كابت للمناعة يصيب الدواجن ابتداءً من عمر 6 أسابيع ولكنه ينتشر عادة في الدجاج البالغ ما بين 12-24 أسبوع وفترة حضانة المرض حوالي 6 أسابيع. المرض وبائي شديد العدوى حيث تصل نسبة النفوق في القطعان غير المحصنة إلى حوالي 10-30% وقد تصل أحيانًا إلى 80%.\r\n\r\n# النيوكاسل\r\n\r\nيعد النيوكاسل من الأمراض الفيروسية الوبائية السريعة الانتشار والتي تسبب خسائر فادحة للمربي، وهو يعد من أهم الأمراض التي يحاذر منها المربون في مصر. هذا الفيروس له القدرة على إحداث الإصابة بالقطيع إلى 100% وكذلك نسبة النفوق إلى 100%. الفيروس لديه القدرة على إصابة الدجاج والرومي حيث أنها أكثر الأنواع عرضة لهذا المرض، كما أن كلا من الحمام والبط والإوز يصاب بالمرض ولكن بدرجة أقل. عند الإنسان، يظهر أحيانًا كـ (العين الحمراء). الفيروس قادر على الحفاظ على حياته لمدة ثلاثة شهور حيًا في ذبائح الطيور المصابة والمحفوظة في الثلاجة على درجة صفر مئوي، ولكن لا يستطيع العيش عند 50°م لأكثر من دقائق معدودة. بعض المطهرات كالفورمالين والفينول قادرة على قتل الفيروس. تتراوح فترة حضانة المرض ما بين 2-18 يوم حسب شدة الفيروس.\r\n\r\n# الالتهاب الشعبي المعدي\r\n\r\nمرض فيروسي يصيب الدجاج فقط ولا يصيب أي من الطيور الداجنة الأخرى، وتتراوح فترة الحضانة للمرض ما بين 18-36 ساعة، ومدة المرض تكون من 2-6 أيام. تظهر الأعراض على الطيور التي يقل عمرها عن ثلاثة شهور، حيث ترتفع نسبة النفوق لحوالي 25%. الطيور التي أصيبت بالمرض وشُفيت منه تظل حاملة للمناعة طوال عمرها وتنقلها لنسلها عن طريق البيض.\r\n\r\n# الجامبورو\r\n\r\nمرض فيروسي يصيب الدجاج في الأعمار المبكرة ويؤثر على الأنسجة الليمفاوية لحوصلة فابرشيوس. يظهر المرض غالبًا في عمر 3-6 أسابيع. خطورة المرض تكمن في أنه يسبب التهابًا في غدة فابرشيوس المسؤولة عن تكوين المناعة في الأسابيع الأولى من العمر، مما يختل نظام المناعة ويضعف مقاومة الطائر. يطلق عليه أحيانًا (إيدز الدجاج). فترة حضانة المرض من 5-10 أيام، ومدة المرض من 8-10 أيام تقريبًا.\r\n\r\n# الجدري\r\n\r\nمرض الجدري يصيب الدجاج والرومي والطيور البرية، وهو فيروس ينتقل بواسطة البعوض أو الحشرات الأخرى، ومن خلال الجروح والقروح الجلدية. الجروح الناتجة عن الافتراس تسهم في نقل المرض. يبقى الفيروس في البثور الجافة لفترة طويلة قد تتعدى العشرة سنوات، ويحتمل درجة حرارة 60°م لمدة 80 دقيقة. فترة النفوق منخفضة، والطيور التي تشفى تظل حاملة للمناعة طوال عمرها.'),
(11, 'استقبال الكتاكيت', '# قبل استقبال الكتاكيت\n## يجب تهيئة المكان قبل الاستقبال بيوم على الاقل \n- إزالة الفرشة السابقة واستبدالها بفرشة جديدة نظيفة.\n- تنظيف اللمبات وتغيير اللمبات غير الصالحة.\n- تنظيف أجهزة التبريد والتدفئة وإزالة جميع بقايا العلف السابق.\n- إخراج المعالف والمساقي وتنظيفها وتطهيرها وتعريضها لأشعة الشمس لقتل الأمراض.\n- تنظيف أجهزة التهوية (المراوح، القنوات الهوائية، وفتحات التهوية، أجهزة التشغيل).\n- تعقيم المزرعة باستخدام غاز الفورمالدهيد لقتل الحشرات والفطريات.\n- وضع الحواجز الخاصة بالتحضين أسفل لمبات التدفئة لتدفئة الكتكوت في حال كانت الحظائر لا تستخدم التدفئة بالهواء الساخن.\n\n# كيفية استقبال الكتاكيت\n\n- فرش الأرضية بالنشارة في الصيف بسمك 5 سم وفي الشتاء 10 سم.\n- يوضع العلف البادي بعد وصول الكتاكيت مباشرة مع الحرص على عدم تجويع الكتاكيت ولو لفترة قصيرة.\n- توسيع مكان التحضين بعد اليوم 15 نظراً لكبر حجم الكتاكيت ومنع التزاحم.\n- وضع الماء في السقيات داخل مكان التحضين قبل استقبال الكتاكيت بساعتين حتى تأخذ المياه درجة حرارة المكان.\n- تخصيص 20% من مساحة العنبر لتحضين الكتاكيت وغلقها بستائر سميكة لمنع خروج الحرارة.\n- التحضين على درجة حرارة 34-35 مئوية لمدة 3 أيام، ثم تقليل درجة الحرارة تدريجياً كل يومين.\n\n# استقبال الكتاكيت عمر يوم\n\n- يجب البدء بتربية كتكوت سليم ذو صفات وراثية عالية ومن قطيع أمهات خالية من الأمراض مثل الإسهال الأبيض، والتيفود، والميكوبلازما.  \n- يجب أن يكون الكتكوت نشطاً ومتجانس الحجم وكبير، مع عيون لامعة، واستبعاد الكتاكيت غير الملائمة للتربية في البداية.  \n- يجب استقبال الكتاكيت على درجة حرارة لا تقل عن 34°، حيث يتم وضع الدفايات والمياه والعلف قبل 5 ساعات من الاستقبال.  \n- درجة الحرارة المثلى خلال الأيام الثلاثة الأولى هي 33°، ثم تقليلها تدريجياً حتى تصل إلى 22° مع مراعاة مراحل الاستقبال المختلفة.  \n- التهوية مهمة لتجنب تراكم ثاني أكسيد الكربون والأمونيا وبخار الماء.  \n- توفير مساحة أرضية كافية للنمو السليم (1 متر مربع لكل 8 دواجن في الصيف و12 في الشتاء).  \n- أرضية المكان يجب أن تكون مغطاة بطبقات من القش أو نشارة الخشب بسُمك 5-7.5 سم ويجب أن تظل جافة.  \n- الحفاظ على التهوية الجيدة لتعزيز نمو صحي للكتاكيت وتكوين فيتامين د.  \n- إسكان الدواجن يجب أن يوفر حماية من الشمس والمطر والحيوانات المفترسة، مع أرضية مقاومة للرطوبة وسهلة التنظيف.  \n- التغذية يجب أن تحتوي على كميات كافية من الماء، الكربوهيدرات، البروتينات، الدهون، الفيتامينات والمعادن.  \n- شراء أفضل الكتاكيت جودة لتحقيق أقصى الأرباح.'),
(12, 'استهلاك العلف', '## نصائح في استهلاك العلف\n- دفى فراخك كويس تسحب علف كويس وتانى كل المعلومات متكاملة ومرتطبة ببعضها هتظبط حرارة تأكل كويس سحب علف يزيد يديك لحم أكتر تكسب أكتر\n- لو حسيت بإستهلاك قليل شوف فراخك ايه الاخطاء الموجودة ممكن تكون مشكلة حرارة او مشكلة نظافة او مرض ظهر فجأة لازم تكون عينك شغالة وعارف فراخك بتاكل قد ايه متوسط فى اليوم\n- احذر من الاعلاف الى نسبة سمومها عالية \n## ودى بعض النقط الى تراعى فيها الاستهلاك بتاعك ولازم تتبعها\n1. **العلف المتوازن:**  \n   يجب توفير علف متوازن تغذويًا يحتوي على النسب المناسبة من البروتين والدهون والكربوهيدرات، ويجب تغذية الفراخ بكميات مناسبة وفقًا للعمر والوزن.\n\n2. **النوعية:**  \n   يجب استخدام علف عالي الجودة والمصمم خصيصًا لتلبية احتياجات الفراخ البيضاء، ويجب تجنب استخدام العلف الفاسد.\n\n3. **الماء:**  \n   يجب توفير الماء النظيف والعذب بشكل دائم للفراخ، ويجب تغيير الماء بانتظام للحفاظ على نظافته. يزيد استهلاك الفرخ للعلف بزيادة استخدامه للماء.\n\n4. **البيئة:**  \n   يجب توفير بيئة مناسبة للفراخ تحتوي على درجة حرارة ورطوبة مناسبة، ويجب تجنب التعرض للإجهاد والضوضاء والاضطرابات في البيئة المحيطة بالفراخ.\n\n5. **المراقبة:**  \n   يجب مراقبة استهلاك الفراخ للعلف وزيادة وزنها بشكل منتظم، وتعديل كمية العلف وفقًا للحاجة، ومراقبة الفراخ لأي أعراض للمرض أو الوفاة المفاجئة.\n\n### ملحوظة : الفرخ الأبيض يأكل متوسط 3.5 كيلو علف طول الدورة'),
(13, 'اوزان', '## يجب الحذر من بعض النقاط عشان توصل لاحسن وزن\n- الحرارة زى مكلمنا عنها سابقا يجب مراعتها ولا تنزل درجة او درجتين عن المعدل الطبيعى ولا تزيد\n- إختيار علفبنسبة بروتين جيدة على حسب العمر مع مراعاة نسبة السموم تكون قليلة\n- تأكد من عدم تزاحم الفراخ على العلف او المياة\n- لاحظ براز الفراخ اذا كان به إسهال خفيف او مرض كحة بسيط\n- يجب مراعاة برنامج الاظلام أيضا يزيد من وزن الفراخ بشكل ملحوظ فى نهاية الدورة\n- الحذر من وضع كمية كبيرة من المياة تكفى ليوم او يومين  لان المياة المستقرة فترات كبيرة تسبب اسهالات يجب تغيير الماء بين فترة من ٦ ل١٠ سعات ولا تتجاوز ذلك\n# كيفية الوصول إلى الوزن المطلوب\n\n1. **الماء النظيف:**  \n   يجب توفير الماء النظيف والعذب بشكل دائم للفراخ، ويجب تغيير الماء بانتظام للحفاظ على نظافته.\n\n2. **التحكم في درجة الحرارة:**  \n   يجب توفير بيئة دافئة ومريحة للفراخ، ويمكن استخدام مصادر الحرارة المختلفة مثل اللمبات الحرارية أو الأرضيات الدافئة لتوفير هذه البيئة.\n\n3. **الصحة الجيدة:**  \n   يجب مراقبة صحة الفراخ باستمرار، وتلقيحها ضد الأمراض الشائعة، وتوفير الرعاية الصحية اللازمة إذا ظهرت أي أعراض للمرض.\n\n4. **المساحة المناسبة:**  \n   يجب توفير مساحة كافية للفراخ للحركة والنمو، وتوفير بيئة نظيفة وصحية لهم.\n\n5. **التخلص من الإجهاد:**  \n   يجب تقليل مصادر الضوضاء والاضطرابات في البيئة المحيطة بالفراخ، وتجنب التعرض للإجهاد بشكل عام.\n\n### يجب وزن عشر فراخ ثم القسمه على عشرة ليكون المتوسط كما يلي'),
(14, 'درجات الحرارة', '## ليه درجة الحرارة يعتبر عامل مهم\nالحرارة عامل أساسى فى سرعة نمو الفراخ ووجب التحذير منه اى خلل فى درجة الحرارة يسبب مشاكل كتير زى قلة إقبال الفراخ على العلف- ضعف مناعة-برد-نهجان-عطش هيؤدى فى الاخر الى زيادة عدد النافق\n## إزاى اعرف ان الحرارة قليلة او زياد\n- فى حالة لو الحرارة قليلة بتشوف الفراخ مجمعة نفسها فى مكان واحد وعاوزين يدفوا نفسهم - صوت زى كحة او عطسة - قلة معدل النمو عن الطبيعى  \n- لو الحرارة عالية بتلاحظ الفراخ بتنهج وفتحة فمها - وبتبعد عن العلف وفيه اقبال شديد على المياة\n## ايضا نقاط يجب الحذر منها\n- استقبال الكتاكتيت على أرضية ساقعة\n- التأكد من صحةالحرارة قبل استقبال الكتاكيت\n- وضع الطعام والشراب قبل استقبال الكتاكيت بحوالى ٦ ساعات خاصة فى فصل الشتاء كى يأخذ درجة حرارة الغرفة يمكن ايضا تقليل \n- يمكن ايضا وضع  الطعام والشراب قبل استقبال الكتاكيت ب ٢ ساعة فى فصل الصيف \n- يجب التأكد من أن الفراخ موزعة جيدا فى جميع الاوقات هذا مؤشر جيد\n## نقاط يجب مراعاتها أيضا خاصة فى فصل الشتاء\n- قم بالتأكد بقفل الفتحات المباشرة الخاصة بالتهوية\n- اذا كنت تربى على الارض قم بنشر نشارة فى مكان خاص للنوم للحماية من الرطوبة خاصة فى الليل \n- قم برفع سقايات المياة عن الارض حتى لا يبتلوا \n- الحذر ثم الحذر من درجة الحرارة أثناء الليل فى الشتاء قد تقل فجأة بسبب عوامل الجو\n- الكتكوت دايما متصل بالفرشة بتاعتوا لو الفرشة مش نضيفة او فيها رطوبة او مبتلة هتسحب الحرارة من جسمة وكدة تظبيط الحرارة سواء بدفاية او بغير ملوش لازم عشان كدة يجب مراعاة نظافة الارض جيدا خاصة لمن يربى على الارض\n- نقطة مهمة جدا يجب التركيز فيها وهى انه وقت تقلب الحرارة من النهار الى الليل يجب تظبيط وتثبيت درجة الحرارة بمعنى أن تعلى درجة حرارة الدفاية او اللمبة الصفرا او السخان اذا كان درجة الحرارة هتقل مع دخول الليل  والعكس فى طلوع النهار تقلل درجة الحرارة وتظبطها على حسب درجة الحرارة المطلوبة على أساس عمر الكتكوت او الفرخ  وهذا   \n### الجدول التالي يمثل درجات الحرارة باليوم'),
(15, 'نصائح في التربية', '# نصائح\r\n\r\nإذا كنت تخطط لتربية الفراخ البيضاء، فإليك بعض النصائح يمكن أن تفيدك في هذا الصدد:\r\n\r\n- اختر مكانًا مناسبًا لتربية الفراخ البيضاء، يفضل أن يكون مكانًا نظيفًا وجافًا ومحميًا من الرياح والأمطار.\r\n- استخدم تغذية متوازنة ومناسبة للفراخ البيضاء، وتأكد من أنها تحتوي على جميع العناصر الغذائية اللازمة لها.\r\n- يجب توفير مياه نظيفة وعذبة طوال الوقت، ويجب تغييرها بشكل مستمر للحفاظ على نظافة الفراخ وصحتها.\r\n- توفر للفراخ مساحة كافية للحركة والتمدد والتحرك، وحاول تجنب الازدحام الزائد في المساحة المخصصة لها.\r\n- تأكد من توفير درجة حرارة مناسبة للفراخ، خاصة في الأشهر الأولى من حياتها، وتأكد من توفير درجة حرارة معتدلة في الأشهر اللاحقة.\r\n- يجب توفير إضاءة مناسبة للفراخ، وخاصة الإضاءة الطبيعية، ويفضل توفير الإضاءة الاصطناعية في الأشهر القليلة الإضاءة الطبيعية.\r\n- يجب تنظيف المساحة المخصصة للفراخ بشكل منتظم للحفاظ على نظافتها وصحة الفراخ.\r\n- تأكد من توفير تهوية مناسبة للمساحة المخصصة للفراخ، وذلك لتوفير الأكسجين اللازم لها وللحد من انتشار البكتيريا والأمراض.\r\n- تأكد من توفير الرعاية الصحية المناسبة للفراخ البيضاء، وخاصة تطعيماتها وعلاجها من الأمراض والإصابات.\r\n- تأكد من توفير الأمان والحماية المناسبة للفراخ، وخاصة من الحيوانات المفترسة والطيور الجارحة، وتأكد من توفير شبكة أمان حول المساحة المخصصة للفراخ.\r\n'),
(16, 'سلالات الفراخ البيضاء', '# سلالات\r\n\r\nتعتبر تربية الفراخ البيضاء أحد الأنشطة الزراعية الرئيسية في مصر، حيث تمتلك البلاد الإمكانيات الطبيعية والبشرية المناسبة لتحقيق هذا النوع من الإنتاج الداجني. وتتوفر في مصر عدة سلالات من الفراخ البيضاء والتي تختلف في مجالات مثل النمو، الإنتاجية، جودة اللحم والبيض. فيما يلي بعض السلالات الأكثر شيوعًا في مصر:\r\n\r\n- **سلالة روس البيضاء (الأشهر)**  \r\nتعدّ هذه السلالة من أشهر سلالات الفراخ البيضاء في مصر، وهي ذات جودة عالية في الإنتاجية وسرعة النمو. يصل وزن الفرخ من هذه السلالة إلى المستوى المطلوب، ما يجعلها مناسبة جدًا لتربية الدواجن للحصول على اللحوم البيضاء.\r\n\r\n- **سلالة كوب**  \r\nتمتلك سلالة كوب خصائص مماثلة لسلالة هبارد، حيث يمكن تربيتها في ظروف صعبة، وهي تنتج كمية كبيرة من اللحم. كما تمتلك هذه السلالة نسبة عالية من الأحماض الأمينية الضرورية للجسم البشري، مما يجعلها مفضلة للأشخاص الذين يهتمون بالصحة.\r\n\r\n- **سلالة هاي لاين**  \r\nتعتبر سلالة هاي لاين من السلالات الأكثر شهرة في العالم، وهي مستوردة من الدول الأوروبية. وتمتاز بنمو سريع وإنتاجية عالية في اللحم وتستخدم بشكل واسع في مصر لإنتاج اللحم الأبيض.\r\n\r\n- **سلالة كوب 500**  \r\nتمثل سلالة كوب 500 من السلالات الحديثة التي تم تدشينها في مصر، وهي تعتبر من السلالات الهجينة التي تتميز بإنتاجية عالية في اللحم. كما تتميز هذه السلالة بقدرتها على التحمل في ظروف المناخ الصعبة، وتعتبر مثالية للمزارعين الذين يرغبون في تحقيق الأرباح العالية.'),
(17, 'التحصينات', '## إزاى أخد أكتر فايدة ممكن من التحصينات\n- استخدم مياة باردة خالية من الكلور\n- المحافظة على التحصين فى درجة حرارة منخفضة حتى يأتى موعد استخدامة ولا يخرج من الثلاجة الا قبل التحصين بوقت قليل\n- منع الفراخ عن العلف والمياة قبل التحصين ب ٢ ساعة\n- ممنوع تحصين الفراخ الى عندها برد او إسهال يجب معالجة المرض قبل التحصين\n## طريقة تحصين ممكن تتبعها \nيتم تحصين الفراخ خلال الدورة ضد الأمراض الفيروسية مثل الجامبرو، النيوكاسل، والأي بي فقط. هذه التحصينات عبارة عن فيروسات المرض يتم إعطاؤها للطائر لتكسبه مناعة ضد المرض وتفادي الإصابة عند انتشار العدوى. يوجد 3 تحصينات هامة لثلاثة أمراض ويتم إعطاؤها كالتالي:\n\n1. عمر 7 أيام: يتم تحصين نيوكاسل (أما هتشنر أو كلون).  \n2. أحيانًا يتم تحصين انفلونزا ميت مع النيوكاسل ويكون حقن والنيوكاسل تقطير.  \n3. عمر 12 يوم: نقوم بتحصين ضد الجمبورو عترة متوسطة.  \n4. عمر 18 يوم: يتم التحصين مرة أخرى ضد النيوكاسل مع إضافة تحصين ضد مرض الأي بي.'),
(18, 'تطهير العنبر', '## تطهير العنبر ليه مهم\n- يقضى على الفطريات والبكتريا الضارة\n- التطهير يقلل نسبة النفوق والامراض زى الاسهال والكحة \n- نسبة تحويل ممتازة طول ما الفرخ أعد فى نظافة هياكل وهيجيب معاك لحم كتير\n- الكتكوت عند الاستقبال بيكون ضعيف مينفعش يكون فى مكان مش نضيف دة يعرضوا للموت ولو عاش فى مكان مش نظيف مش هيحول معاك العلف لى لحم بسهولة وهتخسر\n- مينفعش أبدا تستقبل كتاكيت فى المكان الا لما تكون مغيرلة الفرشة بتاعت القطيع الى قبلوا وتطهر المكان كويس\n \nبرنامج تطهير مقترح لتنظيف وتطهير عنبر 500م². إن تنظيف وتطهير المزرعة جيدًا يعتبر أهم العوامل للحصول على نتائج جيدة، لذا يجب السماح بفترة كافية (أسبوعين على الأقل) بين انتهاء قطيع واستقبال قطيع جديد. يجب اتباع الإجراءات التالية للحصول على تنظيف وتطهير جيد للعنب:\n## ودة برنامج تطهير يساعدك لو مبتعرفش تطهر\n1. رش ملاثيون على الفرشة (2 لتر/40 لتر ماء) للقضاء على الحشرات والسوس المتواجد بالعنبر فور الانتهاء من البيع.  \n2. إزالة الفرشة والتخلص منها بعيدًا عن المزرعة، ويجب عدم نثرها أو تخزينها قريبًا من المزرعة.  \n3. كنس العنبر وإزالة بقايا السبلة من العنبر وإزالة أي بقايا فرشة بالأرضيات.  \n4. إجراء أعمال الإصلاح والصيانة بالعنبر حيث يتم تفكيك كل الأدوات (المساقي - المعالف - الأطباق البلاستيكية) ونقلها خارج العنبر أو في أحد العنابر، غسلها ثم تطهيرها بمطهر اليود 3%، ثم بالفيروسيد 0.25%، ثم تخزينها لحين الاستخدام.  \n5. غسل الخزانات وخطوط الماء وتطهيرها باستخدام سيد 2000 بمعدل 2% (4 لتر/200 لتر ماء) لإزالة الترسيبات العضوية وغير العضوية ومنع ترسيب الأملاح والشوائب بخطوط العلف، ويترك لمدة 6 ساعات ثم غسلها بالماء.  \n\n## غسيل وتطهير العنبر\n\n- غسل العنبر ببادئ النظافة (لإذابة وإزالة البقايا مثل زرق الطيور، الريش، الزغب) بموتور رش شمسية لعمل رغاوى على الجدران ويترك لمدة ساعة أو نصف ساعة على الأقل بمادة بمعدل 10 لتر/600 لتر ماء (MD cid-S)، ثم غسله جيدًا بالماء العادي المندفع تحت ضغط باستخدام ماكينة غسيل أو موتور رش على جميع الأسطح لإزالة بقايا بادئ النظافة.  \n- ملاحظة هامة: في حالة إصابة القطيع السابق بمرض فيروسي (نيوكاسيل- جمبورو) أو وجود إصابات سابقة بالكلوستريديا أو الكوكسيديا، يتم استخدام صودا كاوية بمعدل 8 كجم/200 لتر ماء ساخن ثم رشها على أرضية العنبر.  \n- تطهير العنبر بمطهر قوي مثل فيرو سيد 0.5% (2 لتر/400 لتر ماء) رزاز خفيف لتغطية المسطح بالكامل.  \n- رش العنبر بالكلور 2%.  \n- التطهير بالفنيك 10% للأرضيات والجزء السفلي للجدران.  \n- رش العنبر بالفورمالين بمعدل 10% (حيث أن الفورمالين تركيز 40%) مع تشغيل الهيتر أو الدفايات لمدة 24 ساعة مع غلق العنبر، ثم تهويته لخروج غاز الفورمالدهيد.  \n\n## بعد جفاف العنبر كليًا يتم الآتي\n\n- إدخال النشارة وفردها بالكامل إن أمكن أو في مكان التحضين مبدئيًا، ويفضل إدخال كل فرشة العنبر مرة واحدة ليتسنى تطهيرها كاملة قبل وصول الكتاكيت.  \n- إدخال مساقي وعلاقات وخلافه وجميع الأدوات الخاصة بالعنبر.  \n- رش العنبر فيروسيد 0.25% (500 سم/200 لتر ماء) أو باليود 1%، رزاز خفيف طبقة كاملة فوق النشارة والستائر والأدوات والمعدات.  \n- غلق العنبر ومنع دخول أي فرد حتى وصول الكتاكيت.'),
(19, 'معدل التحويل الغذائي', '## تعريف معدل التحويل الغذائي\n- معدل التحويل الغذائي مقياس لكفاءة العلف ونسبة تحويلة الى لحوم داخل الطائر\n## أهمية معدل التحويل الغذائي\n- له تأثير مباشر على نسبة التكلفة فى سعر الطائر من مرحلة تسكينة حتى عمر البيع اذا كانت نسبة التحويل جيدة جدا فهذا مؤشر جيد على جودة العلف\n- كلما زادت رعايتك للفرخ زادت نسبة معدل التحويل فتهيئة البيئة المناسبة من حرارة ورطوبة وتهوية وعلف جيد ومياة نظيفة ينعكس كل ذلك على جسم الطائر بالتحويل الغذائي الى لحم مما يدل على الادارة الجيدة\n## عوامل تؤثر على معدل التحويل الغذائي يجب الانتباة لها\n- جودة العلف من ناحية التوازن الغذائي ونسبة البروتين\n- سلالة الطائر(الفرخ) يجب شراء سلالة جيدة\n - البيئة المحيطة وذكرناها سابقا الاهتمام بحرارة ورطوبة ومياة ونظيفة وعلف متوازن\n- الحفاظ على العلف من الهدر يجب ان يكون مستوى العلف بالنسبة للكتكوت فى مكان جيد يستطيع الاكل بدون ان يقوم بالبراز عليه او ان يلقى العلف على الارض\n# نصائح مهمة\n-لا تسترخص العلف وقم باختار العلف الجيد وتجربتة قبل ان تقوم بتسكين القطيع من الطيور او ابحث عن علف جيد السمعة تم تجربتة\n- التأكد من نظافة المياة وتغييرها فى وقت لا يتعدى ال ٦ ساعات \n- اتبع برنامجا صحيا يخبرك بمطلبات فراخك ويوجد أداة هنا على التطبيق تساعدك فى هذا تحت مسمى متطلبات فراخ التسمين\n- تجب ملئ المعالف حتى لا يهدر او يتساقط العلف'),
(20, 'الكفاءة الانتاجية', '# عوامل زيادة الكفاءة الانتاجية\n- مساحة المكان الجيد يجب الانتباة ان يكون المجيد غير ضيق وغير واسع زيادة عن اللزوم\n- تهيئة البيئة او المكان جيدا لاستقبال الكتكوت\n- الحفاظ على المكان التنظيف بصفة دورية ومتابعة مناخ العمل\n- سلالة كتكوت يتمتع بصفات وراثية جيد\n- التغذية الجيدة من ماء جيدة\n- التعاون الجيد وادارة المكان والتنسيق الجيد مع العامل يضمن الحفاظ على بيئة العمل والحصول على كفاءة انتاجية عالية\n- ببساطة الكفاءة الانتاجية تأتى عن طريق التعاون والحفاظ على بيئة العمل\n# زيادة الكفاءة الانتاجية\n- اشتري كتكوت من مصدر موثوق\n- استثمر جيدا فى علف جيد واشتري نوعا ذو سمعة جيدة عن تجارب الاخرين\n- اضبط المكان او بيئة العمل \n- اختبار الاوزان واختيار فراخ عشوائية وقم بوزنها للتأكد أنك تعمل بشكل جيد \n- الاهتمام بالفيتامينات والمعادن داخل جسم الفرخ\n- الاهتمام بساعات الاظلام ولدينا اداة تساعدك بذلك تحت مسمى ساعات الاظلاظ\n- مراقبة العنبر جيدا وتسجيل ملاحظات والعمل بها \n- الخلاصة زيادة الكفاءة الانتاجية هي نتاج تطبيق مجموعة من الاجراءات العلمية والعملية للاستمرار والحفاظ على التعاون الدائم فى العمل وهذا ما يوفرة تطبيق فرخة');
